mapper.select:
SELECT 
FROM medication_task

    user_id = #{userId}

        AND task_date  >=  #{startDate}


        AND task_date  <=  #{endDate}


        AND medicine_id IN (
        SELECT id FROM medicine WHERE user_id = #{userId} AND name LIKE CONCAT("%", #{medicineName}, "%")
        )


        AND status = #{status}


ORDER BY task_date DESC, time_point DESC

mapper.update:
UPDATE medication_task
SET status = #{status},
    operate_time = #{operateTime}
WHERE id = #{id} AND status != #{status}

mapper.select:
SELECT 
FROM medication_task
WHERE status = 0
AND task_date = #{currentDate}
AND CONCAT(#{currentDate}, ' ', time_point)  <  #{currentTime}

SELECT COUNT(*) FROM medication_task
WHERE user_id = #{userId}
  AND task_date = #{date}
  AND status = #{status}

SELECT COUNT(*) FROM medication_task
WHERE user_id = #{userId}
  AND task_date = #{date}
